```typescript file=src/rate_limiter.ts
/**
 * Per-key token-bucket rate limiter.
 *
 * Each key (e.g. user id, IP, route) gets its own bucket with `capacity`
 * tokens that refills at `refillPerSec` tokens/second.
 *
 *   - `tryAcquire(key, cost?)` returns true and consumes tokens if available,
 *     false otherwise. Never blocks.
 *   - `acquire(key, cost?)`    resolves once enough tokens are available,
 *     sleeping until the bucket has refilled. Rejects immediately if
 *     refillPerSec === 0 and the request cannot be satisfied.
 *
 * Design notes:
 *   - Buckets are created lazily on first access and evicted after idleTtlMs
 *     of inactivity to prevent unbounded memory growth.
 *   - Refill is computed on-demand (no background timer) using elapsed wall
 *     time, capped at capacity so bursts after long idle stay bounded.
 *   - The clock is injectable for deterministic testing.
 */

export type ClockFn = () => number;

export interface RateLimiterOptions {
  /** Maximum tokens a bucket can hold. Must be > 0. */
  capacity: number;
  /** Tokens added per second. Must be >= 0. Zero means a fixed cap with no refill. */
  refillPerSec: number;
  /** Idle TTL (ms): buckets unused for this long are garbage-collected on the next op. */
  idleTtlMs?: number;
  /** Injectable monotonic clock in ms — defaults to performance.now(). Useful for tests. */
  now?: ClockFn;
}

interface Bucket {
  tokens: number;
  lastRefill: number; // ms (monotonic)
  lastTouched: number; // ms (monotonic) — for idle eviction
}

export class RateLimiter {
  private readonly capacity: number;
  private readonly refillPerSec: number;
  private readonly idleTtlMs: number;
  private readonly now: ClockFn;
  private readonly buckets: Map<string, Bucket> = new Map();

  constructor(opts: RateLimiterOptions) {
    const { capacity, refillPerSec } = opts;

    // Validate capacity: must be a finite number strictly greater than zero.
    if (typeof capacity !== "number" || !isFinite(capacity) || capacity <= 0) {
      throw new RangeError(
        `capacity must be a finite number > 0, got ${capacity}`
      );
    }
    // Validate refillPerSec: must be a finite number >= 0 (zero = no refill).
    if (typeof refillPerSec !== "number" || !isFinite(refillPerSec) || refillPerSec < 0) {
      throw new RangeError(
        `refillPerSec must be a finite number >= 0, got ${refillPerSec}`
      );
    }

    this.capacity = capacity;
    this.refillPerSec = refillPerSec;
    this.idleTtlMs = opts.idleTtlMs ?? 60_000;
    this.now =
      opts.now ??
      (typeof performance !== "undefined" && typeof performance.now === "function"
        ? () => performance.now()
        : () => Date.now());
  }

  /**
   * Attempt to consume `cost` tokens immediately. Returns true on success.
   * Never blocks.
   */
  tryAcquire(key: string, cost = 1): boolean {
    if (cost <= 0) {
      throw new RangeError("cost must be > 0");
    }
    if (cost > this.capacity) {
      // A request that can never fit must not stall the bucket forever.
      throw new RangeError("cost exceeds capacity");
    }
    const bucket = this.getBucket(key);
    this.refill(bucket);
    if (bucket.tokens >= cost) {
      bucket.tokens -= cost;
      return true;
    }
    return false;
  }

  /**
   * Wait until `cost` tokens are available, then consume them.
   * Resolves promptly when capacity is available; otherwise sleeps until
   * the next refill could satisfy the request.
   *
   * Rejects immediately with an Error if refillPerSec === 0 and the bucket
   * cannot satisfy the cost — tokens will never grow, so waiting forever
   * would be a silent hang.
   */
  async acquire(key: string, cost = 1): Promise<void> {
    if (cost <= 0) {
      throw new RangeError("cost must be > 0");
    }
    if (cost > this.capacity) {
      throw new RangeError("cost exceeds capacity");
    }

    // Fast path: tokens already available.
    if (this.tryAcquire(key, cost)) {
      return;
    }

    // If the refill rate is zero, tokens can never grow — reject immediately
    // instead of looping forever.
    if (this.refillPerSec === 0) {
      throw new Error(
        "acquire: insufficient tokens and refillPerSec is 0 — request can never be satisfied"
      );
    }

    // Slow path: sleep until enough tokens have accumulated, then consume.
    const bucket = this.getBucket(key);
    while (true) {
      this.refill(bucket);
      if (bucket.tokens >= cost) {
        bucket.tokens -= cost;
        return;
      }
      const waitMs = this.msUntilTokens(bucket, cost);
      await sleep(waitMs);
    }
  }

  /** Current available token count for `key` (after applying refill). */
  available(key: string): number {
    const bucket = this.getBucket(key);
    this.refill(bucket);
    return bucket.tokens;
  }

  /** Remove the bucket for `key` (e.g. after the user logs out). */
  reset(key: string): void {
    this.buckets.delete(key);
  }

  /** Remove all buckets. */
  clear(): void {
    this.buckets.clear();
  }

  /** Number of live buckets (post-eviction). For diagnostics and tests. */
  size(): number {
    this.evictIdle();
    return this.buckets.size;
  }

  private getBucket(key: string): Bucket {
    this.evictIdle();
    const t = this.now();
    let b = this.buckets.get(key);
    if (b === undefined) {
      b = { tokens: this.capacity, lastRefill: t, lastTouched: t };
      this.buckets.set(key, b);
    } else {
      b.lastTouched = t;
    }
    return b;
  }

  private refill(bucket: Bucket): void {
    const t = this.now();
    const elapsedSec = (t - bucket.lastRefill) / 1000;
    if (elapsedSec <= 0) return;
    const added = elapsedSec * this.refillPerSec;
    // Cap at capacity so a long idle period never grants more than a full bucket.
    bucket.tokens = Math.min(this.capacity, bucket.tokens + added);
    bucket.lastRefill = t;
    bucket.lastTouched = t;
  }

  private msUntilTokens(bucket: Bucket, cost: number): number {
    if (this.refillPerSec <= 0) {
      return 1_000;
    }
    const needed = cost - bucket.tokens;
    if (needed <= 0) return 0;
    return Math.max(1, Math.ceil((needed / this.refillPerSec) * 1000));
  }

  private evictIdle(): void {
    if (this.idleTtlMs <= 0) return;
    const t = this.now();
    for (const [key, b] of this.buckets) {
      if (t - b.lastTouched > this.idleTtlMs) {
        this.buckets.delete(key);
      }
    }
  }
}

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}
